// src/components/Options.js
import React from 'react';
import styles from '../styles/Options.module.css';

const options = [
  { id: 1, label: 'YouTube' },
  { id: 2, label: 'TV' },
  { id: 3, label: 'Bạn bè/gia đình' },
  { id: 4, label: 'Tìm kiếm Google' },
  { id: 5, label: 'Tin tức/báo chí/blog' },
  { id: 6, label: 'TikTok' },
  { id: 7, label: 'Facebook/Instagram' },
  { id: 8, label: 'Khác' },
];

const Options = () => {
  return (
    <div className={styles.optionsContainer}>
      {options.map(option => (
        <button key={option.id} className={styles.optionButton}>
          {option.label}
        </button>
      ))}
    </div>
  );
};

export default Options;
